  `slug` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `fecha_activacion` date NOT NULL,
  `es_recurrente` tinyint(1) NOT NULL,
  `activa` tinyint(1) NOT NULL,
  `contexto` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `cita_filosofica` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `autor_cita` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `pregunta_1` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `pregunta_2` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `pregunta_3` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `pregunta_4` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `pregunta_5` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `accion_sugerida` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
