--
-- Table structure for table `entrenos_entrenorealizado`
--

DROP TABLE IF EXISTS `entrenos_entrenorealizado`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `entrenos_entrenorealizado` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `fecha` date NOT NULL,
  `procesado_gamificacion` tinyint(1) NOT NULL,
  `fuente_datos` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `liftin_workout_id` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `hora_inicio` time(6) DEFAULT NULL,
  `hora_fin` time(6) DEFAULT NULL,
  `duracion_minutos` int unsigned DEFAULT NULL,
  `numero_ejercicios` int unsigned DEFAULT NULL,
  `tiempo_total_formateado` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `calorias_quemadas` int unsigned DEFAULT NULL,
  `frecuencia_cardiaca_promedio` int unsigned DEFAULT NULL,
  `frecuencia_cardiaca_maxima` int unsigned DEFAULT NULL,
  `volumen_total_kg` decimal(10,2) NOT NULL,
  `nombre_rutina_liftin` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notas_liftin` longtext COLLATE utf8mb4_unicode_ci,
  `fecha_importacion` datetime(6) DEFAULT NULL,
  `cliente_id` bigint NOT NULL,
  `rutina_id` bigint NOT NULL,
  `puntos_ganados` int unsigned NOT NULL,
  `records_rotos` int unsigned NOT NULL,
  PRIMARY KEY (`id`),
  KEY `entrenos_entrenoreal_rutina_id_1daae88e_fk_rutinas_r` (`rutina_id`),
  KEY `entreno_cliente_fecha_idx` (`cliente_id`,`fecha`),
  CONSTRAINT `entrenos_entrenoreal_cliente_id_36210975_fk_clientes_` FOREIGN KEY (`cliente_id`) REFERENCES `clientes_cliente` (`id`),
  CONSTRAINT `entrenos_entrenoreal_rutina_id_1daae88e_fk_rutinas_r` FOREIGN KEY (`rutina_id`) REFERENCES `rutinas_rutina` (`id`),
  CONSTRAINT `entrenos_entrenorealizado_chk_1` CHECK ((`duracion_minutos` >= 0)),
  CONSTRAINT `entrenos_entrenorealizado_chk_2` CHECK ((`numero_ejercicios` >= 0)),
  CONSTRAINT `entrenos_entrenorealizado_chk_3` CHECK ((`calorias_quemadas` >= 0)),
  CONSTRAINT `entrenos_entrenorealizado_chk_4` CHECK ((`frecuencia_cardiaca_promedio` >= 0)),
  CONSTRAINT `entrenos_entrenorealizado_chk_5` CHECK ((`frecuencia_cardiaca_maxima` >= 0)),
  CONSTRAINT `entrenos_entrenorealizado_chk_6` CHECK ((`puntos_ganados` >= 0)),
  CONSTRAINT `entrenos_entrenorealizado_chk_7` CHECK ((`records_rotos` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=259 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

