INSERT INTO `estiramientos_estiramientoejercicio` VALUES (1,'Inclinación lateral de cuello (Izquierda)','SUPERIOR','Cuello / Trapecio','Lleva la oreja al hombro suavemente. Mantén el hombro contrario abajo.','estiramientos/inclinacion_lateral_de_cuello_izquierda.gif',1),(2,'Inclinación lateral de cuello (Derecha)','SUPERIOR','Cuello / Trapecio','Respira profundo. No fuerces, solo deja caer la cabeza por su peso.','estiramientos/inclinacion_lateral_de_cuello_derecha.gif',1),(3,'Estiramiento de hombro cruzado (Izquierdo)','SUPERIOR','Deltoides posterior','Cruza el brazo por delante del pecho. Empuja suave con la otra mano.','estiramientos/estiramiento_de_hombro_cruzado_izquierdo.gif',1),(4,'Estiramiento de hombro cruzado (Derecho)','SUPERIOR','Deltoides posterior','Mantén el hombro relajado, no lo subas hacia la oreja.','estiramientos/estiramiento_de_hombro_cruzado_derecho.gif',1),(5,'Estiramiento de tríceps (Izquierdo)','SUPERIOR','Tríceps','Lleva la mano detrás de la cabeza. Empuja el codo hacia abajo.','estiramientos/estiramiento_de_triceps_izquierdo.gif',1),(6,'Estiramiento de tríceps (Derecho)','SUPERIOR','Tríceps','Mantén la cabeza recta, no la inclines hacia adelante.','estiramientos/estiramiento_de_triceps_derecho.gif',1),(7,'Estiramiento pectoral en pared (Izquierdo)','SUPERIOR','Pectoral','Brazo en 90° contra la pared. Gira el torso hacia el lado contrario.','estiramientos/estiramiento_pectoral_en_pared_izquierdo.gif',1),(8,'Estiramiento pectoral en pared (Derecho)','SUPERIOR','Pectoral','Siente el estiramiento en el pecho. Respira lento y profundo.','estiramientos/estiramiento_pectoral_en_pared_derecho.gif',1),(9,'Estiramiento dorsal en pared (Izquierdo)','SUPERIOR','Dorsal ancho','Manos en la pared, caderas hacia atrás. Hunde el pecho hacia el suelo.','estiramientos/estiramiento_dorsal_en_pared_izquierdo.jpg',1),(10,'Estiramiento dorsal en pared (Derecho)','SUPERIOR','Dorsal ancho','Brazos extendidos, siente el estiramiento en el lateral del torso.','estiramientos/estiramiento_dorsal_en_pared_derecho.jpg',1),(11,'Zancada baja - flexor cadera (Izquierda)','INFERIOR','Psoas / Flexor de cadera','Rodilla trasera en el suelo. Aprieta el glúteo y empuja la cadera adelante.','estiramientos/zancada_baja_flexor_cadera_izquierda.gif',1),(12,'Zancada baja - flexor cadera (Derecha)','INFERIOR','Psoas / Flexor de cadera','Mantén el torso erguido. No arquees la espalda baja.','estiramientos/zancada_baja_flexor_cadera_derecha.gif',1),(13,'Estiramiento de cuádriceps de pie (Izquierdo)','INFERIOR','Cuádriceps','Agarra el tobillo y lleva el talón al glúteo. Rodillas juntas.','estiramientos/estiramiento_de_cuadriceps_de_pie_izquierdo.jpg',1),(14,'Estiramiento de cuádriceps de pie (Derecho)','INFERIOR','Cuádriceps','Si necesitas equilibrio, apóyate en una pared.','estiramientos/estiramiento_de_cuadriceps_de_pie_derecho.jpg',1),(15,'Isquiotibiales sentado (Izquierda)','INFERIOR','Isquiotibiales','Pierna estirada, flexiona desde la cadera. Espalda recta.','estiramientos/isquiotibiales_sentado_izquierda.jpg',1),(16,'Isquiotibiales sentado (Derecha)','INFERIOR','Isquiotibiales','Llega hasta donde puedas sin redondear la espalda.','estiramientos/isquiotibiales_sentado_derecha.jpg',1),(17,'Figura 4 - Glúteo/Piriforme (Izquierdo)','INFERIOR','Glúteo / Piriforme','Tumbado boca arriba. Tobillo sobre rodilla contraria. Tira de la pierna base.','estiramientos/figura_4_gluteo_piriforme_izquierdo.jpg',1),(18,'Figura 4 - Glúteo/Piriforme (Derecho)','INFERIOR','Glúteo / Piriforme','Mantén la cabeza en el suelo. Relaja los hombros.','estiramientos/figura_4_gluteo_piriforme_derecho.jpg',1),(19,'Estiramiento de aductores (Mariposa)','INFERIOR','Aductores','Plantas de los pies juntas. Deja caer las rodillas suavemente.','estiramientos/estiramiento_de_aductores_mariposa.gif',1),(20,'Estiramiento de aductores (Lateral)','INFERIOR','Aductores','Piernas abiertas, inclínate hacia un lado. Mantén 15s cada lado.','estiramientos/estiramiento_de_aductores_lateral.gif',1),(21,'Gemelo en pared (Izquierdo)','INFERIOR','Gemelo','Manos en pared, pierna atrás estirada. Talón pegado al suelo.','estiramientos/gemelo_en_pared_izquierdo.png',1),(22,'Gemelo en pared (Derecho)','INFERIOR','Gemelo','Inclínate hacia la pared hasta sentir el estiramiento.','estiramientos/gemelo_en_pared_derecho.png',1),(23,'Rotación de cuello (suave)','COMPLETO','Cuello','Gira lentamente la cabeza en círculos. 5 en cada dirección.','estiramientos/rotacion_de_cuello_suave.gif',1),(24,'Círculos de hombros','COMPLETO','Hombros','Brazos relajados. Haz círculos grandes con los hombros hacia atrás.','estiramientos/circulos_de_hombros.gif',1),(25,'Estiramiento de tríceps (ambos lados)','COMPLETO','Tríceps','30 segundos: 15s cada brazo. Codo apuntando arriba.','estiramientos/estiramiento_de_triceps_ambos_lados.gif',1),(26,'Estiramiento lateral de torso (Izquierda)','COMPLETO','Oblicuos / Dorsal','Brazo arriba, inclínate al lado contrario. Siente el costado.','estiramientos/estiramiento_lateral_de_torso_izquierda.jpg',1),(27,'Estiramiento lateral de torso (Derecha)','COMPLETO','Oblicuos / Dorsal','Mantén las caderas quietas, solo mueve el torso superior.','estiramientos/estiramiento_lateral_de_torso_derecha.jpg',1),(28,'Gato-Vaca','COMPLETO','Columna','En cuadrupedia: arquea y redondea la espalda alternadamente.','estiramientos/gato_vaca.jpg',1),(29,'Zancada con rotación (Izquierda)','COMPLETO','Flexor cadera / Torso','En zancada, rota el torso hacia la pierna adelantada.','estiramientos/zancada_con_rotacion_izquierda.jpg',1),(30,'Zancada con rotación (Derecha)','COMPLETO','Flexor cadera / Torso','Combina estiramiento de cadera con movilidad de columna.','estiramientos/zancada_con_rotacion_derecha.jpg',1),(31,'Isquiotibiales de pie (Izquierda)','COMPLETO','Isquiotibiales','Pierna en superficie elevada. Flexiona desde la cadera.','estiramientos/isquiotibiales_de_pie_izquierda.jpg',1),(32,'Isquiotibiales de pie (Derecha)','COMPLETO','Isquiotibiales','Mantén la espalda recta, no redondees.','estiramientos/isquiotibiales_de_pie_derecha.jpg',1),(33,'Estiramiento de glúteo cruzado (Izquierdo)','COMPLETO','Glúteo','De pie o sentado, cruza tobillo sobre rodilla.','estiramientos/estiramiento_de_gluteo_cruzado_izquierdo.jpg',1),(34,'Estiramiento de glúteo cruzado (Derecho)','COMPLETO','Glúteo','Inclínate hacia adelante manteniendo la espalda recta.','estiramientos/estiramiento_de_gluteo_cruzado_derecho.jpg',1),(35,'Flexión hacia adelante (Ragdoll)','COMPLETO','Isquios / Espalda','De pie, déjate caer hacia adelante. Brazos colgando, relaja el cuello.','estiramientos/flexion_hacia_adelante_ragdoll_kjoUOqu.jpg',1),(36,'Respiración profunda final','COMPLETO','Relajación','De pie, brazos arriba al inhalar, abajo al exhalar. 5 respiraciones.','',1);
