INSERT INTO `logros_arquetipo` VALUES (1,'Saitama (inicio)','El Aspirante Calvo','Todo poder comienza con 100 flexiones, 100 abdominales, 100 sentadillas y 10km de carrera.',0,'fas fa-fist-raised','https://i.pinimg.com/1200x/33/f0/e3/33f0e36b3bd39b997c89fe5a2bb5e74b.jpg'),(2,'Rock Lee','El Genio del Esfuerzo','Sin talento natural, solo trabajo duro. La dedicación supera cualquier don innato.',500,'fas fa-running','https://i.pinimg.com/1200x/40/05/1e/40051e464e1755d470c9e6eaf088a787.jpg'),(3,'Krillin','El Guerrero Humano','Aunque seas el más débil, tu corazón valiente te hace fuerte.',750,'fas fa-circle','https://i.pinimg.com/736x/42/4a/d2/424ad291f7fa89924d718e89fc4ea076.jpg'),(4,'Yamcha','El Lobo del Desierto','Incluso los derrotados pueden encontrar su momento de gloria.',1000,'fas fa-paw','https://i.pinimg.com/736x/34/cb/e4/34cbe43b82bcedb43615f8260926e785.jpg'),(5,'Tien Shinhan','El Guerrero de Tres Ojos','La disciplina marcial trasciende los límites humanos.',1250,'fas fa-eye','https://i.pinimg.com/736x/f1/62/01/f162011915fc69ea7285ad1096f8a296.jpg'),(6,'Roronoa Zoro','El Espadachín Perdido','Tres espadas, una voluntad inquebrantable. Tu determinación corta cualquier obstáculo.',1500,'fas fa-sword','https://i.pinimg.com/736x/7c/04/02/7c04024703988235b0106755450fe928.jpg'),(7,'Sanji','El Cocinero de Pierna Negra','Un verdadero caballero protege a quienes ama con pasión ardiente.',1750,'fas fa-fire','https://cdn.theanimegallery.com/theanimegallery/e014fd23-105d-438b-9cca-54942603c5ab-roronoa-zoro-wallpaper.webp'),(8,'Kenshiro','El Puño de la Estrella del Norte','Ya estás muerto... para la mediocridad. Tu técnica es letal, tu corazón compasivo.',2000,'fas fa-star','https://i.pinimg.com/736x/98/dc/ef/98dcef752867f79da99276c433e76168.jpg'),(9,'Edward Elric','El Alquimista de Acero','Entiendes el intercambio equivalente: para ganar algo, debes sacrificar algo de igual valor.',2250,'fas fa-atom','https://pm1.aminoapps.com/6525/577d5e877ba90a6a171a6b1e4291c9e23c6ead90_hq.jpg'),(10,'Alphonse Elric','El Alma de Acero','Un corazón gentil en una armadura inquebrantable. La bondad es tu mayor fortaleza.',2500,'fas fa-shield','https://alchetron.com/cdn/alphonse-elric-58b6b32c-eff7-429b-94b2-ffb846b209f-resize-750.jpeg'),(11,'Inuyasha','El Medio Demonio','Entre dos mundos, perteneces a ambos. Tu naturaleza dual es tu mayor fortaleza.',3000,'fas fa-paw','https://alchetron.com/cdn/inuyasha-character-4bb24e5b-630c-4008-9f0f-77f3843bcf8-resize-750.jpeg'),(12,'Sesshomaru','El Señor Demonio','La perfección no se busca, se nace con ella. Tu orgullo es tu poder.',3500,'fas fa-moon','https://images4.alphacoders.com/975/thumb-1920-975158.jpg'),(13,'Yusuke Urameshi','El Detective Espiritual','De delincuente a salvador. Tu energía espiritual refleja tu crecimiento como persona.',4000,'fas fa-ghost','https://i.pinimg.com/1200x/5e/22/79/5e22793a1cf30c767b4371aa20eb3e02.jpg'),(14,'Hiei','El Demonio de las Llamas','Las llamas del inframundo arden en tu interior. Rápido, letal, implacable.',4500,'fas fa-fire','https://wallpapers.com/images/high/hiei-from-yuyu-hakusho-pq79isd5ognc02aj.webp'),(15,'Kurama','El Zorro Demonio','La inteligencia y la astucia superan la fuerza bruta. Eres estrategia pura.',5000,'fas fa-leaf','https://images8.alphacoders.com/683/thumb-1920-683164.jpg'),(16,'Ichigo Kurosaki','El Shinigami Sustituto','Proteges a los que amas sin importar el costo. Tu determinación trasciende la muerte.',5500,'fas fa-sword','https://images6.alphacoders.com/137/1374522.png'),(17,'Rukia Kuchiki','La Shinigami de Hielo','Elegante como la nieve, letal como el hielo. Tu belleza oculta un poder mortal.',6000,'fas fa-snowflake','https://picfiles.alphacoders.com/630/630954.jpeg'),(18,'Byakuya Kuchiki','El Noble de los Pétalos','La nobleza no es un título, es una forma de vida. Tu honor es inquebrantable.',6500,'fas fa-leaf','https://www.baltana.com/files/wallpapers-7/Byakuya-Kuchiki-Best-Wallpaper-21523.jpg'),(19,'Jotaro Kujo','El Cruzado Estelar','Yare yare daze. Tu Stand refleja tu alma: preciso, poderoso e implacable.',7000,'fas fa-star','https://i.pinimg.com/1200x/34/43/67/344367ffa26a0bf308806ed9f55613bc.jpg'),(20,'Dio Brando','El Vampiro del Tiempo','Has rechazado tu humanidad. El tiempo mismo se detiene ante tu voluntad.',7500,'fas fa-clock','https://i.pinimg.com/1200x/9a/fb/88/9afb8800bc0748e501461d79feab831b.jpg'),(21,'Natsu Dragneel','El Dragon Slayer de Fuego','El fuego de la amistad arde en tu corazón. Por tus nakama, puedes quemar el mundo.',8000,'fas fa-fire','https://i.pinimg.com/736x/8a/05/f8/8a05f8bc68ea133cdfe452afd0c06d9a.jpg'),(22,'Erza Scarlet','La Reina de las Hadas','Tu armadura no solo protege tu cuerpo, sino el corazón de tus compañeros.',8500,'fas fa-shield','https://i.pinimg.com/1200x/a7/85/0b/a7850b7694e5ceb3bb83121b97604631.jpg'),(23,'Gray Fullbuster','El Mago de Hielo','Tu frialdad exterior oculta un corazón ardiente por tus amigos.',9000,'fas fa-snowflake','https://i.pinimg.com/736x/26/50/72/265072206f70417a9b744f54b33ce796.jpg'),(24,'Laxus Dreyar','El Dragon Slayer del Rayo','El rayo que una vez destruyó, ahora protege. Has encontrado tu verdadero poder.',9500,'fas fa-bolt','https://i.pinimg.com/736x/5e/a8/83/5ea8831833b198c2dd155f0065ef8a48.jpg'),(25,'Gaara','El Kazekage de Arena','La soledad te forjó, pero el amor te transformó. Proteges con arena inquebrantable.',10000,'fas fa-mountain','https://i.pinimg.com/736x/47/ea/08/47ea084ee32a6cc187098c8f327870dc.jpg'),(26,'Kakashi Hatake','El Ninja Copia','Has copiado mil técnicas, pero tu mayor poder es proteger a tus estudiantes.',10500,'fas fa-eye','https://i.pinimg.com/1200x/a5/7a/bc/a57abc03ca6359ff7b15224fa525a96a.jpg'),(27,'Might Guy','La Bestia Verde','La juventud arde eternamente en tu espíritu. El trabajo duro nunca traiciona.',11000,'fas fa-running','https://i.pinimg.com/736x/d5/65/f3/d565f3b0b67f1c394b8661ced4e4a1f2.jpg'),(28,'Jiraiya','El Sabio Pervertido','Detrás de tu personalidad excéntrica se oculta la sabiduría de un verdadero maestro.',11500,'fas fa-frog','https://i.pinimg.com/736x/c8/79/eb/c879ebe8b20fb10d304f6dcbb3fcc3cd.jpg'),(29,'Orochimaru','La Serpiente Sannin','La inmortalidad es tu obsesión. Cambias de cuerpo como una serpiente cambia de piel.',12000,'fas fa-snake','https://i.pinimg.com/736x/95/a4/ff/95a4ff6d0fbbd38d84b58ada46e24410.jpg'),(30,'Tsunade','La Princesa Babosa','Tus puños pueden quebrar montañas, pero tu corazón puede sanar cualquier herida.',12500,'fas fa-fist-raised','https://i.pinimg.com/1200x/58/96/7c/58967c6c6527416d5e16940d6890dcb0.jpg'),(31,'All Might','El Símbolo de la Paz','Un verdadero héroe no se mide por su fuerza, sino por cómo inspira a otros.',13000,'fas fa-shield-alt','https://i.pinimg.com/1200x/81/0b/d3/810bd38bb207508408bf1b999fdd1b69.jpg'),(32,'Endeavor','El Héroe de Fuego','Las llamas del esfuerzo arden más brillantes que el talento natural.',13500,'fas fa-fire','https://i.pinimg.com/736x/45/f4/ab/45f4abaf4eed1e21d39f3361270ad310.jpg'),(33,'Shoto Todoroki','El Heredero Dividido','Hielo y fuego en perfecta armonía. Has aprendido a abrazar ambos lados de tu poder.',14000,'fas fa-yin-yang','https://i.pinimg.com/736x/7e/3e/4d/7e3e4df08654eea42cdd622302ffd8dc.jpg'),(34,'Yujiro Hanma','El Ogro Más Fuerte','La fuerza física pura en su máxima expresión. Eres una calamidad natural con forma humana.',14500,'fas fa-dumbbell','https://i.pinimg.com/1200x/41/bb/1c/41bb1ce9c0cc7ef31d98c2941f7f66d5.jpg'),(35,'Baki Hanma','El Campeón Joven','Llevas la sangre del ogro, pero tu corazón humano te hace más fuerte que tu padre.',15000,'fas fa-fist-raised','https://i.pinimg.com/736x/53/06/02/5306021a4b7f1f4a1903c3b430f36ddc.jpg'),(36,'Saber','El Rey de los Caballeros','Excalibur brilla con la luz de tus ideales. Eres el rey que el mundo necesita.',15500,'fas fa-crown','https://i.pinimg.com/1200x/8c/9e/fc/8c9efc1ce861b9e8eb50a8e07f32450e.jpg'),(37,'Gilgamesh','El Rey de los Héroes','Posees todos los tesoros del mundo. Tu arrogancia está justificada por tu poder absoluto.',16000,'fas fa-gem','https://i.pinimg.com/1200x/cd/29/b0/cd29b064413c8b4ae08c3f0ea0e796a5.jpg'),(38,'Escanor','El León del Orgullo','Durante el día, eres la encarnación del orgullo. Tu poder crece con el sol.',16500,'fas fa-sun','https://i.pinimg.com/736x/8e/d9/f0/8ed9f05b273041c2cb95c8a1009fc8a6.jpg'),(39,'Meliodas','El Capitán de los Pecados','El poder demoníaco y el corazón humano coexisten en ti. Lideras con fuerza y compasión.',17000,'fas fa-dragon','https://i.pinimg.com/1200x/f7/b8/26/f7b82689011a63d3190cc8b85cc70d24.jpg'),(40,'Ban','El Zorro de la Codicia','Tu inmortalidad te ha enseñado el verdadero valor de la vida y el amor.',17500,'fas fa-heart','https://i.pinimg.com/1200x/e0/3c/3c/e03c3ce24b8669f4530a4b62e27fea4b.jpg'),(41,'Goku Niño','El Pequeño Guerrero','La inocencia combinada con un poder increíble. Tu pureza de corazón es tu mayor fortaleza.',18000,'fas fa-child','https://i.pinimg.com/736x/c4/5e/84/c45e84458d6d3583986567ef2cabcf2c.jpg'),(42,'Vegeta (Saiyan Saga)','El Príncipe Orgulloso','El orgullo Saiyan corre por tus venas. Nunca te conformas con ser segundo.',19000,'fas fa-crown','https://i.pinimg.com/1200x/0c/e0/ff/0ce0ff603347f13c7bd2de9f03b74c0f.jpg'),(43,'Piccolo','El Demonio Redentor','De villano a mentor. Has encontrado la redención a través del sacrificio por otros.',20000,'fas fa-user-ninja','https://i.pinimg.com/736x/52/bc/d6/52bcd61491b18031e2e0a2ac8c4e0ee8.jpg'),(44,'Gohan Adolescente','El Guerrero Académico','Prefieres los libros a las batallas, pero cuando luchas, tu poder no conoce límites.',21000,'fas fa-book','https://i.pinimg.com/1200x/69/3d/55/693d55ffd655cee63f05d110678421bb.jpg'),(45,'Goku (Namek)','El Super Saiyan Legendario','La leyenda se ha hecho realidad. Tu transformación dorada marca una nueva era.',22000,'fas fa-bolt','https://i.pinimg.com/736x/0c/eb/03/0ceb0367c009cf147242ce96e3ea2273.jpg'),(46,'Freezer','El Emperador del Universo','El poder absoluto corrompe absolutamente. Eres la encarnación del mal en su forma más pura.',23000,'fas fa-snowflake','https://i.pinimg.com/736x/76/e0/a5/76e0a5a75859a27e8360f6e4635af133.jpg'),(47,'Cell Perfecto','La Perfección Artificial','Eres la culminación de la ciencia y la evolución. La perfección tiene un precio: la soledad.',24000,'fas fa-dna','https://i.pinimg.com/1200x/78/19/aa/7819aa00ceb5b0a9427a7e39f827314b.jpg'),(48,'Gohan (Cell Games)','El Joven Legendario','Tu ira despertó un poder que ni tu padre poseía. Eres el futuro de los Saiyans.',25000,'fas fa-lightning-bolt','https://i.pinimg.com/1200x/40/4d/4d/404d4dfbbfde7f5662182c2bcf556438.jpg'),(49,'Majin Buu','La Destrucción Inocente','Tu poder destructivo es solo igualado por tu inocencia. Eres caos puro con corazón de niño.',26000,'fas fa-candy-cane','https://i.pinimg.com/1200x/4e/db/06/4edb06bf151d29ea0b6a63cc7a2f7dba.jpg'),(50,'Goku (SSJ3)','El Guerrero Sin Límites','Has roto las barreras de lo posible. Tu sed de batalla trasciende la comprensión mortal.',27000,'fas fa-bolt','https://i.pinimg.com/736x/4d/da/3d/4dda3d51e904d106b8a719bee42076cd.jpg'),(51,'Itachi Uchiha','El Genio Trágico','Sacrificaste todo por la paz. Tu amor por tu hermano trasciende la comprensión.',28000,'fas fa-eye','https://i.pinimg.com/1200x/a8/55/b8/a855b8a8a8aa5411ee55bc42f29876ca.jpg'),(52,'Minato Namikaze','El Rayo Amarillo','Más rápido que la luz, más brillante que el sol. Tu legado vive en tu hijo.',29000,'fas fa-bolt','https://i.pinimg.com/1200x/59/21/e1/5921e13ed73166d979f081f59b88bc23.jpg'),(53,'Hashirama Senju','El Dios de los Shinobi','Tu voluntad de fuego ilumina el camino hacia la paz. Eres el ideal de todos los Hokage.',30000,'fas fa-tree','https://i.pinimg.com/1200x/03/2c/0a/032c0a1c130fca26fd69ad5eff6265ad.jpg'),(54,'Madara Uchiha','El Fantasma de los Uchiha','Has visto el ciclo infinito de odio. Tu sueño de paz justifica cualquier medio.',32000,'fas fa-eye','https://i.pinimg.com/1200x/01/f3/6e/01f36e84680df17a8c22e5bc7bf0d8af.jpg'),(55,'Naruto (Sabio)','El Jinchūriki Perfecto','Has convertido el odio en amor, la maldición en bendición. Nadie está perdido.',34000,'fas fa-leaf','https://i.pinimg.com/1200x/15/a9/da/15a9da37faff1bce70810ffda9111ba0.jpg'),(56,'Sasuke (Rinnegan)','El Último Uchiha','Has caminado por la oscuridad para proteger la luz. Tu redención es tu mayor victoria.',36000,'fas fa-lightning-bolt','https://i.pinimg.com/1200x/0b/c0/f6/0bc0f66ec217f01903a2d41049668485.jpg'),(57,'Obito (Jinchūriki)','El Sabio Falso','El dolor te transformó en lo que juraste destruir. Buscas crear un mundo sin sufrimiento.',38000,'fas fa-mask','https://i.pinimg.com/736x/48/2e/e0/482ee08f1d9c8fb7ccdc9031f1e71766.jpg'),(58,'Kaguya Ōtsutsuki','La Diosa Conejo','Eres el origen de todo chakra. Tu poder es tan antiguo como la misma creación.',40000,'fas fa-moon','https://i.pinimg.com/736x/e3/1e/28/e31e28daf5006b85f085fae2852598a9.jpg'),(59,'Ichigo (Bankai Final)','El Híbrido Definitivo','Shinigami, Quincy, Hollow y Humano. Eres la convergencia de todos los poderes espirituales.',42000,'fas fa-yin-yang','https://i.pinimg.com/736x/6c/e6/55/6ce655918daf0e4be91b588663e0482c.jpg'),(60,'Aizen Sosuke','El Dios Autoproclamado','Has trascendido los límites de la existencia espiritual. Tu evolución no conoce fin.',44000,'fas fa-gem','https://i.pinimg.com/736x/89/fc/e8/89fce8dca5055cca663ea70a047a11ae.jpg'),(61,'Goku (SSJ God)','El Saiyan Divino','Has alcanzado el reino de los dioses. Tu ki divino trasciende la comprensión mortal.',46000,'fas fa-bolt','https://i.pinimg.com/736x/7a/83/b7/7a83b7793512caedef12e251fa7e3b11.jpg'),(62,'Vegeta (SSJ Blue)','El Príncipe Azul','Has combinado lo divino con lo mortal. Tu orgullo ahora tiene respaldo divino.',48000,'fas fa-crown','https://i.pinimg.com/736x/b0/5e/9b/b05e9b17a0b830474bde56bdfa0a099f.jpg'),(63,'Broly','El Saiyan Legendario','Tu poder crece sin límites cuando la ira te consume. Eres la fuerza bruta personificada.',50000,'fas fa-fire','https://i.pinimg.com/1200x/8a/77/bb/8a77bb02a8016cbbc16d482f2745bdcc.jpg'),(64,'Jiren','El Guerrero de la Justicia','Has trascendido el tiempo mismo con tu fuerza. Tu justicia es absoluta e inquebrantable.',55000,'fas fa-shield','https://i.pinimg.com/1200x/d3/34/05/d33405c01a2c334d34c936904edd845a.jpg'),(65,'Beerus','El Dios de la Destrucción','Mantienes el equilibrio del universo a través de la destrucción. Tu poder es caprichoso pero necesario.',60000,'fas fa-cat','https://i.pinimg.com/736x/e1/03/b7/e103b74f5a1731c86e188be9b34d2d2a.jpg'),(66,'Whis','El Ángel Instructor','Eres la calma en la tormenta. Tu sabiduría y poder guían incluso a los dioses.',65000,'fas fa-feather','https://i.pinimg.com/1200x/9a/20/6a/9a206a52a7d072439c000cb61bd6783a.jpg'),(67,'Gogeta Blue','La Fusión Divina','Dos guerreros divinos se convierten en uno. Tu poder combinado desafía la lógica.',70000,'fas fa-users','https://i.pinimg.com/736x/6f/13/8f/6f138f7d4f455e096a6d6a110dbfa207.jpg'),(68,'Vegito Blue','El Guerrero Fusionado','La rivalidad se convierte en sinergia perfecta. Eres más que la suma de tus partes.',75000,'fas fa-infinity','https://i.pinimg.com/736x/9b/92/45/9b9245e3623e7e0ad7e127248df53dc1.jpg'),(69,'Moro','El Devorador de Planetas','Absorbes la energía de mundos enteros. Tu hambre de poder no conoce límites.',80000,'fas fa-black-hole','https://i.pinimg.com/1200x/bf/14/de/bf14de89a82b91b5c1f9b8b9dc8ff578.jpg'),(70,'Gas','El Más Fuerte del Universo','Has obtenido el título de más fuerte, pero el poder sin propósito es vacío.',85000,'fas fa-crown','https://i.pinimg.com/736x/1c/90/dc/1c90dc15bf849d394c2af61eefc883ed.jpg'),(71,'Sailor Moon','La Guerrera de la Luna','En nombre de la Luna, castigas a los malvados. Tu amor puede purificar cualquier oscuridad.',90000,'fas fa-moon','https://i.pinimg.com/736x/f8/37/6c/f8376c50e4e281890f82768b875f7909.jpg'),(72,'Seiya de Pegaso','El Caballero de Pegaso','Tu cosmo arde con la fuerza de las estrellas. Proteges a Athena con tu vida.',95000,'fas fa-horse','https://i.pinimg.com/1200x/24/a4/f5/24a4f548b885490a6281bf3afc4e2dab.jpg'),(73,'Saga de Géminis','El Caballero Dorado','Tu alma dual refleja la complejidad del bien y el mal. Eres luz y oscuridad.',100000,'fas fa-yin-yang','https://i.pinimg.com/736x/98/36/cc/9836cc90d2f4c8d39f5eac425107f992.jpg'),(74,'Shaka de Virgo','El Hombre Más Cercano a Dios','Tu iluminación trasciende lo físico. Eres la sabiduría hecha poder.',110000,'fas fa-lotus','https://i.pinimg.com/736x/d8/49/6a/d8496a7959ba814c2e15921ff64afe90.jpg'),(75,'Athena','La Diosa de la Guerra','Proteges la Tierra con amor y justicia. Tu sabiduría guía a tus caballeros.',120000,'fas fa-shield','https://i.pinimg.com/736x/e8/ef/99/e8ef9957bf8a2ec5149950fbf176421a.jpg'),(76,'Hades','El Señor del Inframundo','Gobiernas sobre la muerte misma. Tu dominio se extiende más allá de la comprensión mortal.',130000,'fas fa-skull-crossbones','https://i.pinimg.com/736x/99/d9/cc/99d9cc3bd9975d8493c66d4f948d840f.jpg'),(77,'Simon','El Perforador de Cielos','Tu taladro puede perforar los cielos mismos. Representas la evolución y el progreso infinito.',140000,'fas fa-rocket','https://i.pinimg.com/736x/4f/34/a7/4f34a7ecb7f9c971d0b651c1d099a3e7.jpg'),(78,'Anti-Spiral','La Negación de la Evolución','Representas la estasis absoluta. Tu misión es prevenir que el universo se autodestruya.',150000,'fas fa-ban','https://i.pinimg.com/736x/69/bd/c1/69bdc19ba6a5efe6efbeca867997e810.jpg'),(79,'Tengen Toppa Gurren Lagann','El Robot del Tamaño del Multiverso','Tu tamaño trasciende las dimensiones físicas. Eres la manifestación de la voluntad humana.',160000,'fas fa-robot','https://i.pinimg.com/1200x/d0/4f/54/d04f54cb857dcf0211470022e679e87d.jpg'),(80,'Super Tengen Toppa','La Evolución Conceptual','Has trascendido la forma física para convertirte en el concepto mismo de la evolución.',170000,'fas fa-dna','https://i.pinimg.com/736x/76/91/56/769156818c77b448c7371bf82bf891af.jpg'),(81,'Madoka Kaname','La Diosa de la Esperanza','Te sacrificaste para reescribir las leyes del universo. Tu amor trasciende el espacio y el tiempo.',180000,'fas fa-heart','https://i.pinimg.com/736x/d9/4c/5e/d94c5e43c445c22a5ac8ab402becb128.jpg'),(82,'Homura Akemi','El Demonio del Tiempo','Has reescrito la realidad por amor. Tu devoción trasciende el bien y el mal.',190000,'fas fa-clock','https://i.pinimg.com/736x/24/a5/e2/24a5e2bdaab657a3ea4b92559fb790f0.jpg'),(83,'Haruhi Suzumiya','La Diosa Inconsciente','Sin saberlo, tu voluntad moldea la realidad. Tu aburrimiento puede destruir y crear universos.',200000,'fas fa-magic','https://i.pinimg.com/736x/61/21/f3/6121f30efe30530b47839cae3af54aa6.jpg'),(84,'Truth','La Verdad Universal','Eres la representación de toda la verdad y conocimiento. Existes en la puerta de la verdad absoluta.',220000,'fas fa-door-open','https://i.pinimg.com/736x/02/bd/21/02bd2105aa523248e9b1485e15a9aa7f.jpg'),(85,'Giorno Giovanna (GER)','El Requiem Dorado','Puedes resetear cualquier acción a cero. Tu voluntad dorada puede negar la realidad misma.',240000,'fas fa-undo','https://i.pinimg.com/736x/e7/38/73/e738739d0b9c90bbf8e260f29f25eaf9.jpg'),(86,'Rimuru Tempest','El Señor Demonio Slime','De simple slime a señor demonio. Tu evolución no conoce límites ni fronteras.',260000,'fas fa-circle','https://i.pinimg.com/736x/de/70/39/de7039d3b9c592fd0822ec79f19b42bd.jpg'),(87,'Ainz Ooal Gown','El Rey No-Muerto','Gobiernas desde las sombras con sabiduría estratégica. La muerte es solo el comienzo.',280000,'fas fa-skull','https://i.pinimg.com/736x/cb/f6/cd/cbf6cd5d87df0475455baddd0321ddfa.jpg'),(88,'Saitama','El Héroe por Hobby','Has roto tu limitador. Tu fuerza es tan absoluta que has perdido la emoción de la batalla.',300000,'fas fa-fist-raised','https://i.pinimg.com/1200x/81/a1/ea/81a1ea18c0804f8aedf7622f15d70498.jpg'),(89,'Zeno Sama','El Rey de Todo','Con un gesto puedes borrar universos enteros. Tu inocencia infantil contrasta con tu poder absoluto.',350000,'fas fa-crown','https://i.pinimg.com/736x/9e/f1/f1/9ef1f1a821e74f40461973d32b0b3459.jpg'),(90,'Daishinkan','El Gran Sacerdote','Eres el ángel de los ángeles. Tu sabiduría y poder son los pilares de la existencia multiversal.',400000,'fas fa-praying-hands','https://i.pinimg.com/736x/1c/67/f8/1c67f875504e1bcbcc02bd0de926bc59.jpg'),(91,'Yogiri Takatou','La Muerte Absoluta','Puedes matar cualquier cosa, incluso conceptos abstractos. La muerte misma te obedece.',450000,'fas fa-skull','https://i.pinimg.com/1200x/3b/d5/d3/3bd5d35cdac8e4a49ac8dc3f5d294e4e.jpg'),(92,'Arceus','El Dios Creador Original','Creaste el universo desde la nada. Eres el alfa y omega de toda existencia.',500000,'fas fa-ring','https://i.pinimg.com/1200x/d3/b9/a6/d3b9a6a0a5d97e37b0c09aee00735f37.jpg'),(93,'Akuto Sai','El Rey Demonio Omnipotente','Tu magia trasciende la lógica y la razón. Puedes reescribir las leyes fundamentales de la existencia.',550000,'fas fa-magic','https://i.pinimg.com/736x/f5/80/31/f58031170a2356cfc79e32bcc2699c1f.jpg'),(94,'Featherine Aurora','La Bruja Escritora','Escribes las historias de universos enteros. Para ti, la realidad es solo una narrativa que puedes editar.',600000,'fas fa-feather-alt','https://i.pinimg.com/1200x/7a/72/85/7a72858a4fe49c8ebe3f8d5406e0ef47.jpg'),(95,'Lambdadelta','La Bruja de la Certeza Absoluta','Para ti, lo imposible es solo una palabra. Puedes hacer realidad cualquier cosa con suficiente determinación.',650000,'fas fa-dice','https://i.pinimg.com/736x/5c/8b/ab/5c8babee97cd1e8d8189cbe5450ceace.jpg'),(96,'Bernkastel','La Bruja de los Milagros','Juegas con el destino como si fuera un tablero de ajedrez. Los milagros son tu especialidad.',700000,'fas fa-star','https://i.pinimg.com/1200x/1e/fd/a6/1efda67093e3483290f3a14e9a49bb8e.jpg'),(97,'Kami Tenchi','El Ser Supremo','Existes más allá de todas las dimensiones y conceptos. Eres la fuente de toda existencia.',750000,'fas fa-infinity','https://i.pinimg.com/1200x/ad/0d/cd/ad0dcd17969ae2d41a795bd495344d5a.jpg'),(98,'Hajun','El Caos Absoluto','Representas el caos en su forma más pura. Tu existencia misma amenaza el orden de toda la realidad.',800000,'fas fa-tornado','https://i.pinimg.com/1200x/6d/8e/7c/6d8e7c11046d563cd921f5fe94d21093.jpg'),(99,'Azathoth','El Dios Ciego Idiota','Eres el caos primordial que sueña la realidad. Si despiertas, toda existencia cesará.',900000,'fas fa-eye','https://i.pinimg.com/1200x/25/a2/dd/25a2dd4653770de5aaf42f30fa8607e7.jpg'),(100,'The One Above All','El Uno Sobre Todo lo Absoluto','Eres la omnipotencia absoluta más allá de toda comprensión. Existes más allá de todos los conceptos de poder y existencia.',1000000,'fas fa-eye-of-providence',NULL);
