--
-- Table structure for table `logros_historialpuntos`
--

DROP TABLE IF EXISTS `logros_historialpuntos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `logros_historialpuntos` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `puntos` int unsigned NOT NULL,
  `descripcion` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `fecha` datetime(6) NOT NULL,
  `entreno_id` bigint DEFAULT NULL,
  `perfil_id` bigint NOT NULL,
  `prueba_legendaria_id` bigint DEFAULT NULL,
  `quest_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `logros_historialpunt_entreno_id_f8879c3c_fk_entrenos_` (`entreno_id`),
  KEY `logros_historialpunt_perfil_id_4e0cd489_fk_logros_pe` (`perfil_id`),
  KEY `logros_historialpunt_prueba_legendaria_id_a0f209bc_fk_logros_pr` (`prueba_legendaria_id`),
  KEY `logros_historialpuntos_quest_id_a8ffafab_fk_logros_quest_id` (`quest_id`),
  CONSTRAINT `logros_historialpunt_entreno_id_f8879c3c_fk_entrenos_` FOREIGN KEY (`entreno_id`) REFERENCES `entrenos_entrenorealizado` (`id`),
  CONSTRAINT `logros_historialpunt_perfil_id_4e0cd489_fk_logros_pe` FOREIGN KEY (`perfil_id`) REFERENCES `logros_perfilgamificacion` (`id`),
  CONSTRAINT `logros_historialpunt_prueba_legendaria_id_a0f209bc_fk_logros_pr` FOREIGN KEY (`prueba_legendaria_id`) REFERENCES `logros_pruebalegendaria` (`id`),
  CONSTRAINT `logros_historialpuntos_quest_id_a8ffafab_fk_logros_quest_id` FOREIGN KEY (`quest_id`) REFERENCES `logros_quest` (`id`),
  CONSTRAINT `logros_historialpuntos_chk_1` CHECK ((`puntos` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=646 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

