INSERT INTO `logros_notificacion` VALUES (26,'logro','¡Prueba Legendaria Completada!','Has completado la prueba \'El Primer Puñetazo\' y ganado 50 puntos.',0,'2025-08-30 08:24:07.258000',2),(36,'logro','¡Prueba Legendaria Completada!','Has completado la prueba \'El Primer Puñetazo\' y ganado 50 puntos.',0,'2025-09-06 05:33:01.669000',5),(37,'logro','¡Prueba Legendaria Completada!','Has completado la prueba \'La Rutina Diaria\' y ganado 150 puntos.',0,'2025-09-10 16:50:16.408000',5),(38,'nivel','¡Ascensión Épica!','Has alcanzado el nivel de El Genio del Esfuerzo. Sin talento natural, solo trabajo duro. La dedicación supera cualquier don innato.',0,'2025-09-10 16:50:16.409000',5),(39,'nivel','¡Ascensión Épica!','Has alcanzado el nivel de El Guerrero Humano. Aunque seas el más débil, tu corazón valiente te hace fuerte.',0,'2025-09-15 23:26:27.873000',5),(40,'nivel','¡Ascensión Épica!','Has alcanzado el nivel de El Lobo del Desierto. Incluso los derrotados pueden encontrar su momento de gloria.',0,'2025-09-25 17:49:28.796000',5),(41,'logro','¡Prueba Legendaria Completada!','Has completado la prueba \'El Primer Puñetazo\' y ganado 50 puntos.',0,'2025-09-29 07:27:23.677000',6),(42,'nivel','¡Ascensión Épica!','Has alcanzado el nivel de El Guerrero de Tres Ojos. La disciplina marcial trasciende los límites humanos.',0,'2025-10-04 15:43:59.550000',5),(43,'nivel','¡Ascensión Épica!','Has alcanzado el nivel de El Espadachín Perdido. Tres espadas, una voluntad inquebrantable. Tu determinación corta cualquier obstáculo.',0,'2025-10-11 09:00:04.092000',5),(44,'nivel','¡Ascensión Épica!','Has alcanzado el nivel de El Cocinero de Pierna Negra. Un verdadero caballero protege a quienes ama con pasión ardiente.',0,'2025-10-20 08:56:01.620000',5),(45,'nivel','¡Ascensión Épica!','Has alcanzado el nivel de El Puño de la Estrella del Norte. Ya estás muerto... para la mediocridad. Tu técnica es letal, tu corazón compasivo.',0,'2025-10-29 16:57:42.165000',5),(46,'nivel','¡Ascensión Épica!',